{"code": "import json
import pandas as pd
import re

# Load data from storage
businesses = locals()['var_functions.query_db:36']
reviews_file = locals()['var_functions.query_db:32']

# Load reviews from file if needed
if isinstance(reviews_file, str) and reviews_file.endswith('.json'):
    with open(reviews_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_file

# Extract states and business IDs
def extract_state(description):
    if description and isinstance(description, str):
        match = re.search(r'[A-Za-z\s]+, ([A-Z]{2})', description)
        if match:
            return match.group(1)
    return None

def extract_biz_num(biz_id):
    match = re.search(r'_(\d+)', biz_id) if biz_id else None
    return match.group(1) if match else None

# Build business lookup
biz_lookup = {}
for b in businesses:
    state = extract_state(b.get('description', ''))
    biz_id = b.get('business_id', '')
    num_id = extract_biz_num(biz_id)
    review_count = int(b.get('review_count', 0))

    if state and num_id:
        biz_lookup[num_id] = {
            'state': state,
            'review_count': review_count,
            'business_id': biz_id
        }

print('Found', len(biz_lookup), 'businesses with state info')

# Process reviews and aggregate by state
state_reviews = {}
state_ratings = {}
state_counts = {}

for review in reviews:
    biz_ref = review.get('business_ref', '')
    num_id = extract_biz_num(biz_ref)
    rating = int(review.get('rating', 0))

    if num_id and num_id in biz_lookup:
        state = biz_lookup[num_id]['state']

        # Accumulate review counts from business collection
        if state not in state_reviews:
            state_reviews[state] = biz_lookup[num_id]['review_count']
        else:
            state_reviews[state] += biz_lookup[num_id]['review_count']

        # Accumulate ratings for average calculation
        if state not in state_ratings:
            state_ratings[state] = rating
            state_counts[state] = 1
        else:
            state_ratings[state] += rating
            state_counts[state] += 1

# Calculate statistics
results = []
for state in state_reviews:
    total_reviews = state_reviews[state]
    avg_rating = state_ratings[state] / state_counts[state] if state in state_ratings else 0
    num_reviews_used = state_counts.get(state, 0)

    results.append({
        'state': state,
        'total_reviews': total_reviews,
        'avg_rating': round(avg_rating, 2),
        'sample_size': num_reviews_used
    })

# Sort by total reviews
df_results = pd.DataFrame(results)
df_results = df_results.sort_values('total_reviews', ascending=False)

print('\nState Review Summary:')
for _, row in df_results.iterrows():
    print(f"{row['state']}: {row['total_reviews']} reviews, avg rating {row['avg_rating']} (sample: {row['sample_size']})")

# Top result
top_state = df_results.iloc[0]

print('\n__RESULT__:')
print(json.dumps({
    'top_state': top_state['state'],
    'total_reviews': int(top_state['total_reviews']),
    'avg_rating': float(top_state['avg_rating']),
    'sample_size': int(top_state['sample_size'])
}))"}

