{"code": "import json
import pandas as pd
import re

# Load all business data from storage
businesses = locals()['var_functions.query_db:44']
reviews_file = locals()['var_functions.query_db:32']

# Load reviews from file if needed
if isinstance(reviews_file, str) and reviews_file.endswith('.json'):
    with open(reviews_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_file

# Extract state from description
def get_state(desc):
    if desc and isinstance(desc, str):
        m = re.search(r', ([A-Z]{2})', desc)
        return m.group(1) if m else None
    return None

# Process businesses - extract state and numeric ID
biz_state = {}
biz_num_to_id = {}
state_reviews_total = {}
review_count_per_biz = {}

for b in businesses:
    desc = b.get('description', '')
    state = get_state(desc)
    biz_id = b.get('business_id', '')

    # Extract numeric ID from business_id (format: businessid_X)
    m = re.search(r'businessid_(\d+)', biz_id)
    if m:
        num_id = m.group(1)
        biz_state[num_id] = state
        biz_num_to_id[num_id] = biz_id
        review_count_per_biz[num_id] = int(b.get('review_count', 0))

        if state:
            if state not in state_reviews_total:
                state_reviews_total[state] = 0
            state_reviews_total[state] += int(b.get('review_count', 0))

print('States found:', list(state_reviews_total.keys()))
print('Total reviews by state:', state_reviews_total)

# Extract numeric ID from business_ref and aggregate ratings by state
state_ratings_sum = {}
state_ratings_count = {}

for r in reviews:
    biz_ref = r.get('business_ref', '')
    m = re.search(r'businessref_(\d+)', biz_ref)
    if m:
        num_id = m.group(1)
        if num_id in biz_state and biz_state[num_id]:
            state = biz_state[num_id]
            rating = int(r.get('rating', 0))

            state_ratings_sum[state] = state_ratings_sum.get(state, 0) + rating
            state_ratings_count[state] = state_ratings_count.get(state, 0) + 1

print('Rating counts by state:', state_ratings_count)

# Find state with most reviews
if state_reviews_total:
    top_state = max(state_reviews_total.items(), key=lambda x: x[1])
    state_name = top_state[0]
    total_reviews = top_state[1]

    # Calculate average rating for top state
    avg_rating = 0
    if state_name in state_ratings_count and state_ratings_count[state_name] > 0:
        avg_rating = state_ratings_sum[state_name] / state_ratings_count[state_name]

    result = {
        'state': state_name,
        'total_reviews': total_reviews,
        'avg_rating': round(avg_rating, 2),
        'reviews_sampled': state_ratings_count.get(state_name, 0)
    }
else:
    result = {'error': 'No state data found'}

print('__RESULT__:')
print(json.dumps(result))"}

