    biz_id = b.get('business_id', '')
    num_id = extract_biz_num(biz_id)
    review_count = int(b.get('review_count', 0))

    if state and num_id:
        biz_lookup[num_id] = {
            'state': state,
            'review_count': review_count,
            'business_id': biz_id
        }

