    reviews = json.load(f)

# Map to store state by business number
biz_to_state = {}
state_review_totals = {}

# Process each business
for b in businesses:
    desc = b.get('description', '')
    if desc:
        # Find state code (2 letters after comma)
        state_match = re.search(r', ([A-Z]{2})', desc)
        if state_match:
            state = state_match.group(1)
            biz_id = b.get('business_id', '')
            # Get business number
            num_match = re.search(r'businessid_(\d+)', biz_id)
            if num_match:
                num = num_match.group(1)
                biz_to_state[num] = state
                # Add to state total reviews
                review_count = int(b.get('review_count', 0))
                state_review_totals[state] = state_review_totals.get(state, 0) + review_count

# Aggregate ratings by state
state_rating_sums = {}
state_rating_counts = {}

for r in reviews:
    biz_ref = r.get('business_ref', '')
    num_match = re.search(r'businessref_(\d+)', biz_ref)
    if num_match:
        num = num_match.group(1)
        if num in biz_to_state:
            state = biz_to_state[num]
            rating = int(r.get('rating', 0))
            state_rating_sums[state] = state_rating_sums.get(state, 0) + rating
            state_rating_counts[state] = state_rating_counts.get(state, 0) + 1

# Find state with highest total reviews
if state_review_totals:
    top_state = max(state_review_totals, key=state_review_totals.get)
    total_reviews = state_review_totals[top_state]
    avg_rating = 0
    if top_state in state_rating_counts and state_rating_counts[top_state] > 0:
        avg_rating = state_rating_sums[top_state] / state_rating_counts[top_state]

    result = {
        'state': top_state,
        'total_reviews': total_reviews,
        'avg_rating': round(avg_rating, 2)
    }
else:
    result = {'error': 'No state data found'}

print('__RESULT__:')
print(json.dumps(result))"}
